def interpolation_search(arr, target):
    low = 0
    high = len(arr) - 1

    while low <= high and target >= arr[low] and target <= arr[high]:
        # Eğer arr[low] ve arr[high] aynı ise, bu aralıktaki tüm elemanlar aynıdır.
        # Bu durumda bölme hatasını (ZeroDivisionError) önlemek için özel bir kontrol yapılır.
        if arr[low] == arr[high]:
            if arr[low] == target:
                return low  # Hedef bulundu
            else:
                return -1   # Hedef bu sabit değerli aralıkta değil

        # Ortalama pozisyonu tahmin et
        # Interpolasyon formülü
        pos = low + ((target - arr[low]) * (high - low)) // (arr[high] - arr[low])

        if arr[pos] == target:
            return pos
        elif arr[pos] < target:
            low = pos + 1
        else:  # arr[pos] > target
            high = pos - 1

    return -1
